#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long A; scanf("%lld", &A);
        long long B, C;
        if(A==2){
            B = 4; C = 8;
        }else{
            B = 2*A;
            C = A*A;
        }
        printf("%lld %lld\n", B, C);
    }
    return 0;
}

